import { useState, useEffect } from "react";

const NOTIFICATION_KEY = "castia.notifications.subscription";

export function useNotifications() {
  const [permission, setPermission] = useState("default");
  const [subscription, setSubscription] = useState(null);

  useEffect(() => {
    if ("Notification" in window) {
      setPermission(Notification.permission);
      const stored = localStorage.getItem(NOTIFICATION_KEY);
      if (stored) {
        setSubscription(JSON.parse(stored));
      }
    }
  }, []);

  const requestPermission = async () => {
    if (!("Notification" in window)) return false;
    const status = await Notification.requestPermission();
    setPermission(status);
    return status === "granted";
  };

  const subscribe = async () => {
    if (!("serviceWorker" in navigator) || !("PushManager" in window)) return null;
    const swRegistration = await navigator.serviceWorker.ready;
    try {
      const sub = await swRegistration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(process.env.REACT_APP_VAPID_PUBLIC_KEY || ""),
      });
      const serialized = JSON.parse(JSON.stringify(sub));
      localStorage.setItem(NOTIFICATION_KEY, JSON.stringify(serialized));
      setSubscription(serialized);
      return sub;
    } catch (err) {
      console.error("Push subscription failed:", err);
      return null;
    }
  };

  const unsubscribe = async () => {
    if (!subscription) return;
    const swRegistration = await navigator.serviceWorker.ready;
    const sub = await swRegistration.pushManager.subscribe({
      userVisibleOnly: true,
      applicationServerKey: urlBase64ToUint8Array(process.env.REACT_APP_VAPID_PUBLIC_KEY || ""),
    });
    await sub.unsubscribe();
    localStorage.removeItem(NOTIFICATION_KEY);
    setSubscription(null);
  };

  const showNotification = (title, options = {}) => {
    if (permission !== "granted") return;
    return new Notification(title, {
      icon: "/icon.svg",
      badge: "/icon.svg",
      ...options,
    });
  };

  return { permission, subscription, requestPermission, subscribe, unsubscribe, showNotification };
}

function urlBase64ToUint8Array(base64String) {
  const padding = 2 - (base64String.length % 4);
  const padded = padding === 2 ? base64String : base64String + ":".repeat(padding);
  const binary = atob(padded.replace(/:/g, "="));
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < bytes.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}